// ========== CONFIGURACI?N ==========
const skuMap = {
  "Cacao Maestro": "664",
  "Camino del chocolate": "663",
  "Wonka por un D?a": "661",
  "Un D?a como Oompa Loompa": "662"
};

const PROPINA_ID = 30;
const PROPINA_POR_PERSONA = 15000;
const SKU_SIN_PROPINA = "663";  // ? Camino del chocolate NO cobra propina

// ========== DATOS DEL WEBHOOK ==========
const query = $('Webhook').item.json.query;
const description = query.x_description;
const numPersonas = Number(query.x_extra3 || 1);
const totalOriginal = Number(query.x_amount || 0);

// ========== VALIDACI?N ==========
const skuExperiencia = skuMap[description];
if (!skuExperiencia) {
  throw new Error(`No se encontr? SKU para: "${description}"`);
}

// ========== L?GICA DE PROPINA ==========
const sinPropina = skuExperiencia === SKU_SIN_PROPINA;

let valorExperiencia;
let propinaTotal;

if (sinPropina) {
  valorExperiencia = totalOriginal;
  propinaTotal = 0;
} else {
  propinaTotal = numPersonas * PROPINA_POR_PERSONA;
  valorExperiencia = totalOriginal - propinaTotal;
}

if (valorExperiencia < 0) {
  throw new Error(`Propina (${propinaTotal}) > Total (${totalOriginal})`);
}

// ========== CONSTRUIR PAYLOAD ==========
const siigoPayload = {
  document: { id: 30537 },
  date: new Date().toISOString().split('T')[0],
  customer: {
    identification: query.x_customer_document
  },
  seller: 10857,
  cost_center: 168,
  payments: [
    {
      id: 13848,
      value: totalOriginal
    }
  ],
  items: [
    {
      code: skuExperiencia,
      description: description,
      quantity: numPersonas,
      price: Math.round(valorExperiencia / numPersonas),
      warehouse: 30
    }
  ]
};

if (propinaTotal > 0) {
  siigoPayload.global_charges = [
    {
      id: PROPINA_ID,
      value: propinaTotal
    }
  ];
}

// ========== RESULTADO ==========
return [{
  json: {
    siigoPayload: siigoPayload,
    resumen: {
      experiencia: description,
      sku: skuExperiencia,
      personas: numPersonas,
      valorExperiencia: valorExperiencia,
      propina: propinaTotal,
      total: totalOriginal,
      sinPropina: sinPropina
    }
  }
}];

